async function fetchAndUpdateMetadata(itemId: string, url: string, retryCount = 0): Promise<void> {
  let db: ReturnType<typeof getDatabase>

  try {
    db = requireDatabase()
  } catch {
    console.warn('[Metadata] No database available, skipping metadata fetch')
    return
