  async encryptItem(
    itemType: SyncItemType,
    itemId: string,
    data: unknown,
    options: {
      operation?: 'create' | 'update' | 'delete'
      clock?: VectorClock
      stateVector?: string
      deleted?: boolean
    } = {}
  ): Promise<EncryptedSyncItem> {
    const vaultKey = await this.getVaultKey()
    const deviceKeyPair = await retrieveDeviceKeyPair()

    if (!deviceKeyPair) {
